-- Repartidor de misiones
lang["#MISSION_GIVER_BOSKNIGHT"] = "Caballero Superior Roberts"
lang["#MISSION_GIVER_BOSKNIGHT_SUBTITLE"] = "Caballero Superior de la Hermandad"
lang["#MISSION_GIVER_BOSKNIGHT_NEW"] = "Debes ser el nuevo Forastero del que todos hablan. Suponiendo que no estés aquí para nada malévolo, te doy la bienvenida a nuestro pequeño paraíso en este agujero helado de mierda."
lang["#MISSION_GIVER_BOSKNIGHT_NO"] = "Tienes suerte de estar vivo. Más suerte aún de que no te haya disparado todavía. O te apartas de nuestro camino o te haces útil."
lang["#MISSION_GIVER_BOSKNIGHT_0"] = "Si eres hábil con una llave inglesa o buscas saquear ruinas del viejo mundo, puede que tenga algunas tareas para ti."
lang["#MISSION_GIVER_BOSKNIGHT_25"] = "Bueno, si no es el Forastero prometedor. Todavía tengo algunas cosas para que hagas si crees que puedes manejarlas."
lang["#MISSION_GIVER_BOSKNIGHT_50"] = "Hasta ahora, todo bien. Yo y el resto de los Caballeros te lo agradecemos, aunque no lo demuestren."
lang["#MISSION_GIVER_BOSKNIGHT_100"] = "No hay necesidad de formalidades. Si necesitas algo, dímelo; de lo contrario, es posible que todavía tengamos algo para ti."
lang["#MISSION_GIVER_BOSKNIGHT_GREET_FINISHED"] = "La Hermandad Prevalece."

-- Misiones
lang["#MISSION_BOSKNIGHT_OLD_WORLD_WARS"] = "Guerras del Viejo Mundo"
lang["#MISSION_BOSKNIGHT_OLD_WORLD_WARS_DESC"] = "Una de las muchas tareas de los Caballeros es mantener el equipo que usan tanto nuestros Paladines como nuestros Escribas. La mayoría de estas cosas son bastante mundanas, desde reparar ventiladores de techo hasta arreglar el percutor de un rifle de asalto. Algunas de las reparaciones más... esotéricas involucran componentes raros y bastante caros. Afortunadamente, algunos lugares aún permanecen intactos y deberían tener las cosas que necesitamos. Uno de estos lugares es el Refugio 7. Ubicado cerca de un pueblo llamado 'Salt Wells' en territorio controlado por la RNC al sur de aquí. Necesito una lata especial de grasa, MIL-PRF-81322, comúnmente usada para las puertas de esos viejos refugios y generalmente considerada como basura por la mayoría, aún deberían tener algo de eso por algún lado."
lang["#MISSION_BOSKNIGHT_OLD_WORLD_WARS_HINT"] = "Encuentra y entra al Refugio 7 en la región de Salt Wells. Busca una lata especial de grasa en algún lugar dentro."
lang["#MISSION_BOSKNIGHT_OLD_WORLD_WARS_COMPLETE"] = "Esto es perfecto. Solo hay que calentarlo para que funcione de nuevo y luego debería estar como nuevo. Oye, antes de que te vayas, un dato curioso. Esto también se usaba en muchos aviones y cazas a reacción antes de la guerra, ¿interesante, verdad?"
lang["#MISSION_BOSKNIGHT_OLD_WORLD_WARS_ITEMNAME"] = "Grasa MIL-PRF-81322"

lang["#MISSION_BOSKNIGHT_LOST_TRANSMISSION"] = "Transmisión Perdida"
lang["#MISSION_BOSKNIGHT_LOST_TRANSMISSION_DESC"] = "Una lección importante en el campo de batalla es la comunicación. Como parte de esa lección, a nosotros los Caballeros y Paladines nos enseñan a usar Radios de Mano para comunicarnos. Lamentablemente, con los años se están volviendo cada vez más difíciles de encontrar y reparar. Por eso he puesto una recompensa por encontrar Radios de Mano o sus piezas."
lang["#MISSION_BOSKNIGHT_LOST_TRANSMISSION_HINT"] = "Encuentra Radios de Mano y tráelas al Caballero Superior Roberts para recibir una recompensa."
lang["#MISSION_BOSKNIGHT_LOST_TRANSMISSION_COMPLETE"] = "Ah, buen hallazgo. Aquí tienes lo que se te debe."

lang["#MISSION_BOSKNIGHT_BUNKER_REPAIRS"] = "Reparaciones del Búnker"
lang["#MISSION_BOSKNIGHT_BUNKER_REPAIRS_DESC"] = "Una de las tareas de los Caballeros implica mantener este búnker en funcionamiento. Eso requiere una gran cantidad de recursos. La mayoría los tenemos cubiertos, pero algunos los usamos constantemente y necesitamos un suministro constante de Placas de Metal. Consígueme algunas y haré que te recompensen."
lang["#MISSION_BOSKNIGHT_BUNKER_REPAIRS_HINT"] = "Adquiere 5 Placas de Metal y tráelas al Caballero Superior Roberts."
lang["#MISSION_BOSKNIGHT_BUNKER_REPAIRS_COMPLETE"] = "Gracias, esto debería ser suficiente."

RELOADSCHEMA = true